      paragrafos: [{"id":"lc80:art-26-p1","numero":"1","texto":"Considera­se como prática forense o exercício profissional de consultoria, assessoria, o cumprimento de estágio nas Defensorias Públicas e o desempenho de cargo, emprego ou função, de nível superior, de atividades eminentemente jurídicas.","alineas":[]},{"id":"lc80:art-26-p1","numero":"1","texto":"Considera-se como atividade jurídica o exercício da advocacia, o cumprimento de estágio de Direito reconhecido por lei e o desempenho de cargo, emprego ou função, de nível superior, de atividades eminentemente jurídicas. .","alineas":[]},{"id":"lc80:art-26-p2","numero":"2","texto":"Os candidatos proibidos de inscrição na Ordem dos Advogados do Brasil comprovarão o registro até a posse no cargo de Defensor Público.","alineas":[]}],
