      numero: "53",
      caput: "A Defensoria Pública do Distrito Federal e dos Territórios compreende:",
      paragrafos: [],
      incisos: [{"id":"lc80:art-53-inc-I","numero":"I","texto":"órgãos de administração superior:","alineas":[{"id":"lc80:art-53-inc-I-a","numero":"a","texto":"a Defensoria Pública-Geral do Distrito Federal e dos Territórios;"},{"id":"lc80:art-53-inc-I-b","numero":"b","texto":"a Subdefensoria Pública-Geral do Distrito Federal e dos Territórios;"},{"id":"lc80:art-53-inc-I-c","numero":"c","texto":"o Conselho Superior da Defensoria Pública do Distrito Federal e dos Territórios;"},{"id":"lc80:art-53-inc-I-d","numero":"d","texto":"a Corregedoria-Geral da Defensoria Pública do Distrito Federal e dos Territórios;"}]},{"id":"lc80:art-53-inc-II","numero":"II","texto":"órgãos de atuação:","alineas":[{"id":"lc80:art-53-inc-II-a","numero":"a","texto":"as Defensorias Públicas do Distrito Federal e dos Territórios;"},{"id":"lc80:art-53-inc-II-b","numero":"b","texto":"os Núcleos da Defensoria Pública do Distrito Federal e dos Territórios;"}]},{"id":"lc80:art-53-inc-III","numero":"III","texto":"órgãos de execução: os Defensores Públicos do Distrito Federal e dos Territórios.","alineas":[]}],
