    {
      tipo: "artigo" as const,
      id: "lc80:art-99",
      numero: "99",
      caput: "A Defensoria Pública do Estado tem por chefe o Defensor Publico-Geral, nomeado pelo Governador do Estado, dentre integrantes da carreira maiores de trinta e cinco anos, na forma disciplinada pela legislação estadual.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "lc80:art-99",
      numero: "99",
      caput: "A Defensoria Pública do Estado tem por chefe o Defensor Público-Geral, nomeado pelo Governador do Estado, dentre membros estáveis da Carreira e maiores de 35 (trinta e cinco) anos, escolhidos em lista tríplice formada pelo voto direto, secreto, plurinominal e obrigatório de seus membros, para mandato de 2 (dois) anos, permitida uma recondução. .",
      paragrafos: [{"id":"lc80:art-99-p1","numero":"1","texto":"O Defensor Publico-Geral será substituído em suas faltas, licenças, férias e impedimentos pelo Subdefensor Publico-Geral, nomeado pelo Governador do Estado, dentre os integrantes da carreira, na forma da legislação estadual.","alineas":[]},{"id":"lc80:art-99-p1","numero":"1","texto":"O Defensor Público-Geral será substituído em suas faltas, licenças, férias e impedimentos pelo Subdefensor Público-Geral, por ele nomeado dentre integrantes estáveis da Carreira, na forma da legislação estadual. .","alineas":[]},{"id":"lc80:art-99-p2","numero":"2","texto":"Os Estados, segundo suas necessidades, poderão ter mais de um Subdefensor Publico-Geral.","alineas":[]},{"id":"lc80:art-99-p3","numero":"3","texto":"O Conselho Superior editará as normas regulamentando a eleição para a escolha do Defensor Público-Geral. .","alineas":[]},{"id":"lc80:art-99-p4","numero":"4","texto":"Caso o Chefe do Poder Executivo não efetive a nomeação do Defensor Público-Geral nos 15 (quinze) dias que se seguirem ao recebimento da lista tríplice, será investido automaticamente no cargo o Defensor Público mais votado para exercício do mandato. .","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"A Defensoria Pública do Estado tem por chefe o Defensor Público-Geral, nomeado pelo Governador do Estado, dentre membros estáveis da Carreira e maiores de 35 (trinta e cinco) anos, escolhidos em lista tríplice formada pelo voto direto, secreto, plurinominal e obrigatório de seus membros, para mandato de 2 (dois) anos, permitida uma recondução. .","redacaoDadaPor":{"lei":"Redação dada pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: O Defensor Público-Geral será substituído em suas faltas, licenças, férias e impedimentos pelo Subdefensor Público-Geral, por ele nomeado dentre integrantes estáveis da Carreira, na forma da legislação estadual. .","redacaoDadaPor":{"lei":"Redação dada pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§3: O Conselho Superior editará as normas regulamentando a eleição para a escolha do Defensor Público-Geral. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§4: Caso o Chefe do Poder Executivo não efetive a nomeação do Defensor Público-Geral nos 15 (quinze) dias que se seguirem ao recebimento da lista tríplice, será investido automaticamente no cargo o Defensor Público mais votado para exercício do mandato. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    },
    {
      tipo: "artigo" as const,
      id: "lc80:art-100",
      numero: "100",
      caput: "Ao Defensor Publico-Geral do Estado compete dirigir a Defensoria Pública do Estado, superintender e coordenar suas atividades, orientando sua atuação, e representando­a judicial e extrajudicialmente.",
      paragrafos: [],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "lc80:art-101",
      numero: "101",
      caput: "O Conselho Superior da Defensoria Pública do Estado é composto pelo Defensor Publico-Geral, pelo Subdefensor Publico-Geral e pelo Corregedor-Geral, como membros natos, e por representantes da categoria mais elevada da carreira, em número e forma a serem fixados em lei estadual.",
      paragrafos: [{"id":"lc80:art-101-púnico","numero":"único","texto":"O Conselho Superior será presidido pelo Defensor Publico-Geral.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [],
    },
    {
      tipo: "artigo" as const,
      id: "lc80:art-101",
      numero: "101",
      caput: "A composição do Conselho Superior da Defensoria Pública do Estado deve incluir obrigatoriamente o Defensor Público-Geral, o Subdefensor Público-Geral, o Corregedor-Geral e o Ouvidor-Geral, como membros natos, e, em sua maioria, representantes estáveis da Carreira, eleitos pelo voto direto, plurinominal, obrigatório e secreto de seus membros, em número e forma a serem fixados em lei estadual. .",
      paragrafos: [{"id":"lc80:art-101-p1","numero":"1","texto":"O Conselho Superior é presidido pelo Defensor Público-Geral, que terá voto de qualidade, exceto em matéria disciplinar. .","alineas":[]},{"id":"lc80:art-101-p2","numero":"2","texto":"As eleições serão realizadas em conformidade com as instruções baixadas pelo Conselho Superior da Defensoria Pública do Estado. .","alineas":[]},{"id":"lc80:art-101-p3","numero":"3","texto":"Os membros do Conselho Superior são eleitos para mandato de 2 (dois) anos, permitida uma reeleição. .","alineas":[]},{"id":"lc80:art-101-p4","numero":"4","texto":"São elegíveis os membros estáveis da Defensoria Pública que não estejam afastados da Carreira. .","alineas":[]},{"id":"lc80:art-101-p5","numero":"5","texto":"O presidente da entidade de classe de maior representatividade dos membros da Defensoria Pública do Estado terá assento e voz nas reuniões do Conselho Superior. .","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"A composição do Conselho Superior da Defensoria Pública do Estado deve incluir obrigatoriamente o Defensor Público-Geral, o Subdefensor Público-Geral, o Corregedor-Geral e o Ouvidor-Geral, como membros natos, e, em sua maioria, representantes estáveis da Carreira, eleitos pelo voto direto, plurinominal, obrigatório e secreto de seus membros, em número e forma a serem fixados em lei estadual. .","redacaoDadaPor":{"lei":"Redação dada pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§1: O Conselho Superior é presidido pelo Defensor Público-Geral, que terá voto de qualidade, exceto em matéria disciplinar. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":3,"texto":"§2: As eleições serão realizadas em conformidade com as instruções baixadas pelo Conselho Superior da Defensoria Pública do Estado. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":4,"texto":"§3: Os membros do Conselho Superior são eleitos para mandato de 2 (dois) anos, permitida uma reeleição. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":5,"texto":"§4: São elegíveis os membros estáveis da Defensoria Pública que não estejam afastados da Carreira. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":6,"texto":"§5: O presidente da entidade de classe de maior representatividade dos membros da Defensoria Pública do Estado terá assento e voz nas reuniões do Conselho Superior. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
    }
