      historico: [{"versao":1,"texto":"A Ouvidoria-Geral é órgão auxiliar da Defensoria Pública do Estado, de promoção da qualidade dos serviços prestados pela Instituição. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null},{"versao":2,"texto":"§único: A Ouvidoria-Geral contará com servidores da Defensoria Pública do Estado e com a estrutura definida pelo Conselho Superior após proposta do Ouvidor-Geral. .","redacaoDadaPor":{"lei":"Incluído pela Lei Complementar nº 132, de 2009","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
