      id: "lc80:art-121",
      numero: "121",
      caput: "A remoção a pedido far­se­á mediante requerimento ao Defensor Publico-Geral, nos quinze dias seguintes à publicação, no Diário Oficial, do aviso de existência de vaga.",
      paragrafos: [{"id":"lc80:art-121-púnico","numero":"único","texto":"Findo o prazo fixado neste artigo e, havendo mais de um candidato à remoção, será removido o mais antigo na categoria e, ocorrendo empate, sucessivamente, o mais antigo na carreira, no serviço público do Estado, no serviço público em geral, o mais idoso e o mais bem classificado no concurso para ingresso na Defensoria Pública.","alineas":[]}],
      incisos: [],
      referencias: [],
      historico: [{"versao":1,"texto":"§único: Findo o prazo fixado neste artigo e, havendo mais de um candidato à remoção, será removido o mais antigo na categoria e, ocorrendo empate, sucessivamente, o mais antigo na carreira, no serviço público do Estado, no serviço público em geral, o mais idoso e o mais bem classificado no concurso para ingresso na Defensoria Pública.","redacaoDadaPor":{"lei":"Vide ADI 7303","artigo":""},"publicadoEm":"","vigenteDesde":"","vigenteAte":null}],
